const listComplianceChecklistItems = `-- name: ListComplianceChecklistItems :many
SELECT
    ci.id, ci.tenant_id, ci.rule_id, ci.worker_profile_id, ci.engagement_id, ci.status, ci.due_date, ci.completed_at, ci.reviewed_at, ci.reviewed_by, ci.evidence_path, ci.evidence_file_name, ci.evidence_content_type, ci.evidence_uploaded_at, ci.evidence_uploaded_by, ci.waiver_reason, ci.waiver_until, ci.waived_at, ci.waived_by, ci.detected_value, ci.notes, ci.metadata, ci.inactive, ci.created_at, ci.created_by, ci.updated_at, ci.updated_by,
    cr.code AS rule_code,
    cr.title AS rule_title,
    cr.category AS rule_category,
    cr.scope AS rule_scope,
    cr.severity AS rule_severity,
    cr.requires_evidence,
    cr.evidence_label,
    cr.blocks_payroll,
    wp.display_name AS worker_display_name,
    wp.worker_code,
    e.title AS engagement_title,
    e.engagement_code
FROM hrms.compliance_checklist_items ci
JOIN hrms.compliance_rules cr ON cr.tenant_id = ci.tenant_id AND cr.id = ci.rule_id AND NOT cr.inactive
LEFT JOIN hrms.worker_profiles wp ON wp.tenant_id = ci.tenant_id AND wp.id = ci.worker_profile_id AND NOT wp.inactive
LEFT JOIN hrms.engagements e ON e.tenant_id = ci.tenant_id AND e.id = ci.engagement_id AND NOT e.inactive
WHERE ci.tenant_id = $1
  AND ($2::uuid IS NULL OR ci.worker_profile_id = $2::uuid)
  AND ($3::uuid IS NULL OR ci.engagement_id = $3::uuid)
  AND ($4::uuid IS NULL OR ci.rule_id = $4::uuid)
  AND ($5::text IS NULL OR ci.status = $5::text)
  AND ($6::text IS NULL OR cr.category = $6::text)
  AND ($7::date IS NULL OR ci.due_date <= $7::date)
  AND (
      $8::text IS NULL
      OR cr.code ILIKE '%' || $8::text || '%'
      OR cr.title ILIKE '%' || $8::text || '%'
      OR wp.display_name ILIKE '%' || $8::text || '%'
      OR wp.worker_code ILIKE '%' || $8::text || '%'
      OR e.title ILIKE '%' || $8::text || '%'
      OR e.engagement_code ILIKE '%' || $8::text || '%'
  )
  AND NOT ci.inactive
ORDER BY
    CASE ci.status
        WHEN 'non_compliant' THEN 1
        WHEN 'expired' THEN 2
        WHEN 'pending' THEN 3
        WHEN 'in_review' THEN 4
        WHEN 'waived' THEN 5
        WHEN 'compliant' THEN 6
        ELSE 7
    END,
    ci.due_date ASC NULLS LAST,
    cr.severity DESC,
    cr.title ASC
`

